#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int A,B,C; scanf("%d %d %d", &A, &B, &C);
        printf("%d\n", C - A);
    }
    return 0;
}

